// DOM tambahan yang dibutuhkan untuk modal edit
const modalOverlay = document.getElementById('modalOverlay');
const editId       = document.getElementById('editId');       // hidden input
const editTitle    = document.getElementById('editTitle');
const editContent  = document.getElementById('editContent');
const btnUpdate    = document.getElementById('btnUpdate');
const btnClose     = document.getElementById('btnCloseModal');

// ===== BUKA MODAL DAN ISI DATA =====
function setupEdit(id) {
  // Cari artikel berdasarkan ID
  const article = articles.find(a => a.id === id);
  if (!article) return;

  // Isi form modal dengan data yang ada
  editId.value      = article.id;       // Simpan ID di hidden input
  editTitle.value   = article.title;
  editContent.value = article.content;

  openModal();
  editTitle.focus(); // Fokus ke field pertama
}

// ===== SIMPAN PERUBAHAN =====
btnUpdate.addEventListener('click', function() {
  const id      = Number(editId.value); // Konversi kembali ke number!
  const title   = editTitle.value.trim();
  const content = editContent.value.trim();

  if (!title || !content) {
    showToast('Judul dan konten wajib diisi!', 'error');
    return;
  }

  // Cari index artikel yang akan diupdate
  const index = articles.findIndex(a => a.id === id);
  if (index !== -1) {
    articles[index].title   = title;    // Perbarui properti
    articles[index].content = content;
    articles[index].updatedAt = new Date().toLocaleDateString('id-ID');
  }

  saveToStorage(); // Simpan perubahan
  renderTable();
  closeModal();
  showToast('Artikel berhasil diperbarui!');
});

// ===== TUTUP MODAL =====
function openModal()  { modalOverlay.classList.add('active');    }
function closeModal() { modalOverlay.classList.remove('active'); }
btnClose.addEventListener('click', closeModal);
modalOverlay.addEventListener('click', e => {
  if (e.target === modalOverlay) closeModal(); // Klik overlay untuk tutup
});

// ===== DELETE SEDERHANA (tanpa konfirmasi) =====
function deleteArticle(id) {
  articles = articles.filter(a => a.id !== id);
  saveToStorage();
  renderTable();
  showToast('Artikel dihapus!');
}

// ===== DELETE DENGAN KONFIRMASI MODAL (lebih baik) =====
let pendingDeleteId = null; // State untuk menyimpan ID yang akan dihapus

function confirmDelete(id) {
  pendingDeleteId = id;
  openConfirmModal(); // Buka modal konfirmasi terpisah
}

// Di modal konfirmasi:
function executeDelete() {
  if (!pendingDeleteId) return;

  articles = articles.filter(a => a.id !== pendingDeleteId);
  saveToStorage();
  renderTable();
  closeConfirmModal();
  showToast('Artikel berhasil dihapus!');

  pendingDeleteId = null; // Reset state
}

// ===== UPDATE renderTable() — Ganti tombol hapus =====
